#### Testing and Error Handling

```solidity
// Test cases for PortfolioManager contract
pragma solidity ^0.8.0;
import "hardhat/console.sol";
import "./PortfolioManager.sol";

contract PortfolioManagerTest {
    PortfolioManager pm;
    IERC20 usdc;

    function setUp() public {
        pm = new PortfolioManager(address(usdc));
        usdc = IERC20(address(pm));
    }

    function testAddAsset() public {
        usdc.mint(address(this), 1000);
        usdc.approve(address(pm), 1000);
        pm.addAsset(address(usdc), 1000);
        assertEq(pm.portfolios(address(this)).totalValue, 1000);
        assertEq(pm.portfolios(address(this)).assetBalances[address(usdc)], 1000);
    }

    function testRemoveAsset() public {
        usdc.mint(address(this), 1000);
        usdc.approve(address(pm), 1000);
        pm.addAsset(address(usdc), 1000);
        pm.removeAsset(address(usdc), 500);
        assertEq(pm.portfolios(address(this)).totalValue, 500);
        assertEq(pm.portfolios(address(this)).assetBalances[address(usdc)], 500);
    }
}
```

